import sys
from collections import defaultdict
input = sys.stdin.readline

def solve():
    n, k = map(int, input().split())
    mines = []
    for _ in range(n):
        x, y, t = map(int, input().split())
        mines.append((x, y, t))

    parent = list(range(n))
    def find(a):
        while parent[a] != a:
            parent[a] = parent[parent[a]]
            a = parent[a]
        return a
    def union(a, b):
        a, b = find(a), find(b)
        if a != b: parent[a] = b

    # Group by row (same y)
    rows = defaultdict(list)
    for i, (x, y, t) in enumerate(mines):
        rows[y].append((x, i))
    for y, lst in rows.items():
        lst.sort()
        for j in range(len(lst)-1):
            if lst[j+1][0] - lst[j][0] <= k:
                union(lst[j][1], lst[j+1][1])

    cols = defaultdict(list)
    for i, (x, y, t) in enumerate(mines):
        cols[x].append((y, i))
    for x, lst in cols.items():
        lst.sort()
        for j in range(len(lst)-1):
            if lst[j+1][0] - lst[j][0] <= k:
                union(lst[j][1], lst[j+1][1])

    comp_min = {}
    for i, (x, y, t) in enumerate(mines):
        r = find(i)
        if r not in comp_min or t < comp_min[r]:
            comp_min[r] = t

    timers = sorted(comp_min.values())
    # Find min T such that number of timers > T <= T+1
    # i.e., count(timers > T) <= T+1
    # Binary search
    lo, hi = 0, 10**9 + 1
    while lo < hi:
        mid = (lo + hi) // 2
        need = len(timers) - (sum(1 for t in timers if t <= mid))
        import bisect
        need = len(timers) - bisect.bisect_right(timers, mid)
        if need <= mid + 1:
            hi = mid
        else:
            lo = mid + 1
    print(lo)

